  1	import { CodeEditor, Language } from '@patternfly/react-code-editor';
  2	import {
  3	  Checkbox,
  4	  Dropdown,
  5	  DropdownItem,
  6	  Flex,
  7	  FlexItem,
  8	  MenuToggle,
  9	  MenuToggleElement,
 10	  Switch
 11	} from '@patternfly/react-core';
 12	import { getSchemaType, WidgetProps } from '@rjsf/utils';
 13	import classNames from 'classnames';
 14	import * as _ from 'lodash';
 15	import * as React from 'react';
 16	import { useTranslation } from 'react-i18next';
 17	import { useTheme } from '../../../utils/theme-hook';
 18	import { jsonSchemaNumberTypes } from './const';
 19	import { DescriptionField } from './fields';
 20	import { AtomicFieldTemplate } from './templates';
 21	
 22	export const TextWidget: React.FC<WidgetProps> = props => {
 23	  const { disabled = false, id, onBlur, onChange, onFocus, readonly = false, schema = {}, value = '' } = props;
 24	  const schemaType = getSchemaType(schema);
 25	  return jsonSchemaNumberTypes.includes(String(schemaType)) ? (
 26	    <NumberWidget {...props} />
 27	  ) : (
 28	    <span
 29	      className={classNames('pf-v6-c-form-control', {
 30	        'pf-m-disabled': disabled,
 31	        'pf-m-readonly': readonly
 32	      })}
 33	    >
 34	      <input
 35	        disabled={disabled}
 36	        id={id}
 37	        key={id}
 38	        onBlur={onBlur && (event => onBlur(id, event.target.value))}
 39	        onChange={({ currentTarget }) => onChange(currentTarget.value, undefined, id)}
 40	        onFocus={onFocus && (event => onFocus(id, event.target.value))}
 41	        readOnly={readonly}
 42	        type="text"
 43	        value={value}
 44	      />
 45	    </span>
 46	  );
 47	};
 48	
 49	export const NumberWidget: React.FC<WidgetProps> = props => {
 50	  const { value, id, onBlur, onChange, onFocus } = props;
 51	  const numberValue = _.toNumber(value);
 52	  return (
 53	    <span className="pf-v6-c-form-control">
 54	      <input
 55	        id={id}
 56	        key={id}
 57	        onBlur={onBlur && (event => onBlur(id, event.target.value))}
 58	        onChange={({ currentTarget }) =>
 59	          onChange(currentTarget.value !== '' ? _.toNumber(currentTarget.value) : '', undefined, id)
 60	        }
 61	        onFocus={onFocus && (event => onFocus(id, event.target.value))}
 62	        type="number"
 63	        value={_.isFinite(numberValue) ? numberValue : ''}
 64	      />
 65	    </span>
 66	  );
 67	};
 68	
 69	export const PasswordWidget: React.FC<WidgetProps> = props => {
 70	  const { value = '', id, onBlur, onChange, onFocus } = props;
 71	  return (
 72	    <span className="pf-v6-c-form-control">
 73	      <input
 74	        key={id}
 75	        id={id}
 76	        type="password"
 77	        onBlur={onBlur && (event => onBlur(id, event.target.value))}
 78	        onChange={({ currentTarget }) => onChange(currentTarget.value, undefined, id)}
 79	        onFocus={onFocus && (event => onFocus(id, event.target.value))}
 80	        value={value}
 81	      />
 82	    </span>
 83	  );
 84	};
 85	
 86	export const SwitchWidget: React.FC<WidgetProps> = props => {
 87	  const { t } = useTranslation('plugin__netobserv-plugin');
 88	  const { value, id, label, onBlur, onChange, onFocus } = props;
 89	  return (
 90	    <Switch
 91	      id={id || label}
 92	      key={id || label}
 93	      isChecked={_.isNil(value) ? false : value}
 94	      onBlur={onBlur && (event => onBlur(id, event.target.value))}
 95	      onChange={(_event, v) => onChange(v, undefined, id)}
 96	      onFocus={onFocus && (event => onFocus(id, event.target.value))}
 97	      label={t('True')}
 98	    />
 99	  );
100	};
101	
102	export const SelectWidget: React.FC<WidgetProps> = props => {
103	  const { t } = useTranslation('plugin__netobserv-plugin');
104	  const { id, label, onBlur, onChange, onFocus, options, schema, value } = props;
105	  const [isOpen, setIsOpen] = React.useState(false);
106	  const { enumOptions = [], title } = options;
107	  return (
108	    <Dropdown
109	      id={id}
110	      isOpen={isOpen}
111	      onBlur={onBlur && (() => onBlur(id, value))}
112	      onSelect={(e, v) => {
113	        onChange(v, undefined, id);
114	        setIsOpen(false);
115	      }}
116	      onFocus={onFocus && (() => onFocus(id, value))}
117	      onOpenChange={(isOpen: boolean) => setIsOpen(isOpen)}
118	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
119	        <MenuToggle id={`${id}-toggle`} ref={toggleRef} onClick={() => setIsOpen(!isOpen)} isExpanded={isOpen}>
120	          {value || t('Select {{title}}', { title: title || schema?.title || label })}
121	        </MenuToggle>
122	      )}
123	    >
124	      {enumOptions.map(option => (
125	        <DropdownItem id={`${id}-${option.value}`} key={option.value} value={option.value}>
126	          {option.label}
127	        </DropdownItem>
128	      ))}
129	    </Dropdown>
130	  );
131	};
132	
133	export const JSONWidget: React.FC<WidgetProps> = props => {
134	  const isDarkTheme = useTheme();
135	
136	  const { disabled = false, id, onBlur, onChange, onFocus, readonly = false, value = '{}' } = props;
137	  return (
138	    <span
139	      className={classNames('pf-v6-c-form-control', {
140	        'pf-m-disabled': disabled,
141	        'pf-m-readonly': readonly
142	      })}
143	    >
144	      <CodeEditor
145	        id={id}
146	        isDarkTheme={isDarkTheme}
147	        isMinimapVisible={false}
148	        isLineNumbersVisible={false}
149	        isLanguageLabelVisible={true}
150	        isReadOnly={readonly || disabled}
151	        code={value}
152	        onBlur={onBlur && (() => onBlur(id, value))}
153	        onChange={v => onChange(v, undefined, id)}
154	        onFocus={onFocus && (() => onFocus(id, value))}
155	        language={Language.json}
156	        height="75px"
157	      />
158	    </span>
159	  );
160	};
161	
162	export const ArrayCheckboxesWidget: React.FC<WidgetProps> = props => {
163	  const { schema, value, id, onBlur, onChange, onFocus } = props;
164	
165	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
166	  const enums = (schema.items as any).enum || [];
167	  const errFunc = (value: string) => () => console.error('Function not implemented.', value);
168	
169	  return (
170	    // since schema type is 'array' and widget is 'checkboxes', we use AtomicFieldTemplate
171	    // to render the field and values all at once without the add/remove buttons
172	    <AtomicFieldTemplate
173	      onKeyChange={errFunc}
174	      onDropPropertyClick={errFunc}
175	      description={<DescriptionField schema={schema} description={schema.description} />}
176	      {...{
177	        ...props,
178	        // eslint-disable-next-line @typescript-eslint/no-explicit-any
179	        style: props.style as React.StyleHTMLAttributes<any> | undefined,
180	        readonly: props.readonly === true,
181	        disabled: props.disabled === true
182	      }}
183	    >
184	      <Flex
185	        className="checkboxes-container"
186	        direction={{ default: enums.length > 4 ? 'row' : 'column' }}
187	        onBlur={() => onBlur(id, value)}
188	        onFocus={() => onFocus(id, value)}
189	      >
190	        {enums.map((option: string, index: number) => (
191	          <FlexItem key={`${id}-${index}`}>
192	            <Checkbox
193	              id={`${id}-${index}`}
194	              data-test-id={`${id}-${option}`}
195	              label={option}
196	              isChecked={_.isNil(value) ? false : value.includes(option)}
197	              onClick={() =>
198	                onChange(
199	                  value.includes(option) ? value.filter((v: string) => v !== option) : [...value, option],
200	                  undefined,
201	                  id
202	                )
203	              }
204	            />
205	          </FlexItem>
206	        ))}
207	      </Flex>
208	    </AtomicFieldTemplate>
209	  );
210	};
211	
212	export default {
213	  BaseInput: TextWidget,
214	  CheckboxWidget: SwitchWidget, // force using switch everywhere for consistency
215	  SwitchWidget,
216	  NumberWidget,
217	  PasswordWidget,
218	  SelectWidget,
219	  TextWidget,
220	  int32: NumberWidget,
221	  int64: NumberWidget,
222	  map: JSONWidget,
223	  arrayCheckboxes: ArrayCheckboxesWidget
224	};

